// Package agentmetrics loads attempt outcomes for Story 11 aggregations
// (success rate, cost, duration per harness/provider/model/tier).
//
// Source priority is FEAT-010 run-store first (.ddx/exec/runs/*.json) with
// .ddx/executions/*/result.json as the legacy fallback. Per-attempt records
// are deduped by AttemptID — run-store wins over bundles when both exist —
// matching the multi-source dedupe used by state_runs.go (ddx-65543530).
//
// Per the Story 11 locked decision, the already_satisfied terminal status
// counts as success. See Bucket.Successful.
package agentmetrics

import "time"

// Source identifies where an Attempt was loaded from.
const (
	SourceRunStore = "run-store"
	SourceBundle   = "bundle"
)

// Attempt is one execute-bead try projected to the fields Story 11
// aggregations need. Cost, duration, and exit_code come from the per-attempt
// result (run record or bundle result.json). Harness/provider/model are
// taken from the result when present and enriched from kind:routing /
// kind:escalation-summary bead events otherwise.
type Attempt struct {
	AttemptID    string    `json:"attempt_id"`
	BeadID       string    `json:"bead_id,omitempty"`
	Harness      string    `json:"harness,omitempty"`
	Provider     string    `json:"provider,omitempty"`
	Model        string    `json:"model,omitempty"`
	Tier         string    `json:"tier,omitempty"`
	Status       string    `json:"status,omitempty"`
	Outcome      string    `json:"outcome,omitempty"`
	Bucket       Bucket    `json:"bucket,omitempty"`
	CostUSD      float64   `json:"cost_usd,omitempty"`
	DurationMS   int       `json:"duration_ms,omitempty"`
	ExitCode     int       `json:"exit_code"`
	StartedAt    time.Time `json:"started_at,omitempty"`
	FinishedAt   time.Time `json:"finished_at,omitempty"`
	InputTokens  int       `json:"input_tokens,omitempty"`
	OutputTokens int       `json:"output_tokens,omitempty"`
	Source       string    `json:"source,omitempty"`
}

// resolver_agent_metrics.go implements the agentMetrics(window, groupBy)
// query (Story 11). Aggregations are computed from the agentmetrics package
// (run-store first, .ddx/executions bundles fallback) and cached per
// (project, axis, window) keyed on a revision fingerprint of the underlying
// data sources. The fingerprint covers the run-store dir, the bundles dir,
// and the .ddx/beads-archive.jsonl file so the cache survives an ADR-004
// archive move (closed beads moved out of beads.jsonl into beads-archive
// flip the fingerprint and force a re-aggregate).
package graphql

import (
	"context"
	"crypto/sha256"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agentmetrics"
)

// agentMetricsCacheEntry is one cached aggregation. fingerprint is the
// revision string the entry was computed against; on lookup the resolver
// recomputes the current fingerprint and serves the entry only when they
// match.
type agentMetricsCacheEntry struct {
	fingerprint string
	result      *AgentMetricsResult
}

// agentMetricsCache is process-global. Multi-project servers key by the
// effective workingDir so two projects never collide.
var agentMetricsCache = struct {
	sync.Mutex
	byKey map[string]agentMetricsCacheEntry
}{byKey: map[string]agentMetricsCacheEntry{}}

// AgentMetrics is the resolver for the agentMetrics field.
func (r *queryResolver) AgentMetrics(ctx context.Context, window AgentMetricsWindow, groupBy AgentMetricsAxis) (*AgentMetricsResult, error) {
	if !window.IsValid() {
		return nil, fmt.Errorf("agentMetrics: invalid window %q", window)
	}
	if !groupBy.IsValid() {
		return nil, fmt.Errorf("agentMetrics: invalid groupBy %q", groupBy)
	}
	wd := r.workingDir(ctx)
	fp := agentMetricsFingerprint(wd)
	cacheKey := wd + "|" + string(window) + "|" + string(groupBy)

	agentMetricsCache.Lock()
	if cached, ok := agentMetricsCache.byKey[cacheKey]; ok && cached.fingerprint == fp {
		agentMetricsCache.Unlock()
		return cached.result, nil
	}
	agentMetricsCache.Unlock()

	attempts, err := agentmetrics.LoadAttempts(wd)
	if err != nil {
		return nil, fmt.Errorf("agentMetrics: load attempts: %w", err)
	}
	cutoff := time.Now().UTC().Add(-windowDuration(window))
	rows := buildAgentMetricsRows(attempts, cutoff, groupBy)
	result := &AgentMetricsResult{
		Window:   window,
		GroupBy:  groupBy,
		Revision: fp,
		Rows:     rows,
	}
	agentMetricsCache.Lock()
	agentMetricsCache.byKey[cacheKey] = agentMetricsCacheEntry{fingerprint: fp, result: result}
	agentMetricsCache.Unlock()
	return result, nil
}

// windowDuration maps the schema enum to a Duration. Falls back to the 7d
// default for unknown values (the IsValid guard above already rejects them).
func windowDuration(w AgentMetricsWindow) time.Duration {
	switch w {
	case AgentMetricsWindowW24h:
		return 24 * time.Hour
	case AgentMetricsWindowW30d:
		return 30 * 24 * time.Hour
	default:
		return 7 * 24 * time.Hour
	}
}

// buildAgentMetricsRows groups attempts by axis, applies the window cutoff,
// and computes per-bucket aggregates. Output is sorted by attempt count
// descending then key ascending so the UI gets a stable ordering.
func buildAgentMetricsRows(attempts []agentmetrics.Attempt, cutoff time.Time, axis AgentMetricsAxis) []*AgentMetricsRow {
	type acc struct {
		durations    []int
		costs        []float64
		inTokens     []int
		outTokens    []int
		successes    int
		totalCost    float64
		lastFinished time.Time
	}
	groups := map[string]*acc{}
	for _, a := range attempts {
		if !a.StartedAt.IsZero() && a.StartedAt.Before(cutoff) {
			continue
		}
		key := axisKey(a, axis)
		if key == "" {
			continue
		}
		g, ok := groups[key]
		if !ok {
			g = &acc{}
			groups[key] = g
		}
		g.durations = append(g.durations, a.DurationMS)
		g.costs = append(g.costs, a.CostUSD)
		g.inTokens = append(g.inTokens, a.InputTokens)
		g.outTokens = append(g.outTokens, a.OutputTokens)
		g.totalCost += a.CostUSD
		if a.Bucket.Successful() {
			g.successes++
		}
		ts := a.FinishedAt
		if ts.IsZero() {
			ts = a.StartedAt
		}
		if !ts.IsZero() && ts.After(g.lastFinished) {
			g.lastFinished = ts
		}
	}

	out := make([]*AgentMetricsRow, 0, len(groups))
	for key, g := range groups {
		attemptCount := len(g.durations)
		row := &AgentMetricsRow{
			Key:              key,
			Attempts:         attemptCount,
			Successes:        g.successes,
			SuccessRate:      ratio(g.successes, attemptCount),
			MeanDurationMs:   meanInt(g.durations),
			P50DurationMs:    percentileInt(g.durations, 50),
			P95DurationMs:    percentileInt(g.durations, 95),
			MeanCostUsd:      meanFloat(g.costs),
			MeanInputTokens:  meanInt(g.inTokens),
			MeanOutputTokens: meanInt(g.outTokens),
		}
		if g.successes > 0 {
			eff := g.totalCost / float64(g.successes)
			row.EffectiveCostPerSuccessUsd = &eff
		}
		if !g.lastFinished.IsZero() {
			s := g.lastFinished.UTC().Format(time.RFC3339)
			row.LastSeenAt = &s
		}
		out = append(out, row)
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].Attempts != out[j].Attempts {
			return out[i].Attempts > out[j].Attempts
		}
		return out[i].Key < out[j].Key
	})
	return out
}

// axisKey extracts the bucket label for one Attempt against one axis. Empty
// string means "skip this attempt for this axis" (e.g. a model-axis bucket
// for a result.json with no model field).
func axisKey(a agentmetrics.Attempt, axis AgentMetricsAxis) string {
	switch axis {
	case AgentMetricsAxisModel:
		return a.Model
	case AgentMetricsAxisHarness:
		return a.Harness
	case AgentMetricsAxisProvider:
		return a.Provider
	case AgentMetricsAxisTier:
		return a.Tier
	}
	return ""
}

func ratio(num, denom int) float64 {
	if denom == 0 {
		return 0
	}
	return float64(num) / float64(denom)
}

func meanInt(xs []int) float64 {
	if len(xs) == 0 {
		return 0
	}
	var sum int
	for _, v := range xs {
		sum += v
	}
	return float64(sum) / float64(len(xs))
}

func meanFloat(xs []float64) float64 {
	if len(xs) == 0 {
		return 0
	}
	var sum float64
	for _, v := range xs {
		sum += v
	}
	return sum / float64(len(xs))
}

// percentileInt returns the nearest-rank percentile of xs (0-100). For p50 on
// an even-length slice it picks the lower of the two middle values; that
// matches Go's standard nearest-rank choice and is sufficient for the
// operator-facing summary.
func percentileInt(xs []int, p int) int {
	if len(xs) == 0 {
		return 0
	}
	sorted := append([]int(nil), xs...)
	sort.Ints(sorted)
	rank := (p * len(sorted)) / 100
	if rank >= len(sorted) {
		rank = len(sorted) - 1
	}
	return sorted[rank]
}

// agentMetricsFingerprint produces a stable revision string for the
// agentmetrics inputs at workingDir. The hash inputs are: the .ddx/exec/runs
// directory listing (name + size + modtime), the .ddx/executions directory
// listing of result.json files, and the .ddx/beads-archive.jsonl file's
// stat. Any add/remove/modify in those sources flips the fingerprint and
// invalidates the cache. The fingerprint survives ADR-004 archive moves
// because the archive file is included.
func agentMetricsFingerprint(workingDir string) string {
	h := sha256.New()
	addDir(h, filepath.Join(workingDir, ".ddx", "exec", "runs"), "")
	addDir(h, filepath.Join(workingDir, ".ddx", "executions"), "result.json")
	addStat(h, filepath.Join(workingDir, ".ddx", "beads-archive.jsonl"))
	addStat(h, filepath.Join(workingDir, ".ddx", "beads.jsonl"))
	return fmt.Sprintf("%x", h.Sum(nil))
}

func addDir(h interface{ Write([]byte) (int, error) }, dir, requireChild string) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		fmt.Fprintf(writerOf(h), "missing:%s\n", dir)
		return
	}
	names := make([]string, 0, len(entries))
	for _, e := range entries {
		names = append(names, e.Name())
	}
	sort.Strings(names)
	for _, name := range names {
		full := filepath.Join(dir, name)
		if requireChild != "" {
			full = filepath.Join(full, requireChild)
		}
		addStat(h, full)
	}
}

func addStat(h interface{ Write([]byte) (int, error) }, path string) {
	info, err := os.Stat(path)
	if err != nil {
		fmt.Fprintf(writerOf(h), "absent:%s\n", path)
		return
	}
	fmt.Fprintf(writerOf(h), "%s:%d:%d\n", path, info.Size(), info.ModTime().UnixNano())
}

// writerOf adapts an io.Writer-like to fmt.Fprintf. Kept tiny so the helpers
// above stay one-liners.
func writerOf(h interface{ Write([]byte) (int, error) }) interface{ Write([]byte) (int, error) } {
	return h
}

package agentmetrics

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

const (
	runStoreSubdir = ".ddx/exec/runs"
	bundlesSubdir  = ".ddx/executions"
)

// LoadAttempts scans the FEAT-010 run-store first, then .ddx/executions
// bundles, and returns one Attempt per execute-bead try. When the same
// AttemptID appears in both sources the run-store record wins. Attempts
// are returned sorted by StartedAt ascending (newest last) so callers
// computing windowed aggregations can take a tail slice.
func LoadAttempts(workingDir string) ([]Attempt, error) {
	enrich, err := loadRoutingEnrichment(workingDir)
	if err != nil {
		return nil, err
	}

	out := make([]Attempt, 0, 64)
	seen := make(map[string]bool)

	rs, err := loadFromRunStore(workingDir)
	if err != nil {
		return nil, err
	}
	for _, a := range rs {
		applyEnrichment(&a, enrich)
		a.Bucket = ClassifyBucket(a.Status)
		a.Tier = TierKey(a.Harness, a.Model)
		out = append(out, a)
		seen[a.AttemptID] = true
	}

	bd, err := loadFromBundles(workingDir)
	if err != nil {
		return nil, err
	}
	for _, a := range bd {
		if seen[a.AttemptID] {
			continue
		}
		applyEnrichment(&a, enrich)
		a.Bucket = ClassifyBucket(a.Status)
		a.Tier = TierKey(a.Harness, a.Model)
		out = append(out, a)
		seen[a.AttemptID] = true
	}

	sort.SliceStable(out, func(i, j int) bool {
		return out[i].StartedAt.Before(out[j].StartedAt)
	})
	return out, nil
}

// TierKey is the canonical "harness/model" tier label used by other Story
// 11 surfaces. An empty model collapses to just the harness.
func TierKey(harness, model string) string {
	if model == "" {
		return harness
	}
	return harness + "/" + model
}

// runRecord mirrors the FEAT-010 run-store JSON shape (subset). Mirrors
// server/state_runs.go runRecord; intentionally not shared so this package
// stays free of the server import graph.
type runRecord struct {
	ID          string  `json:"id"`
	Layer       string  `json:"layer"`
	Status      string  `json:"status"`
	Outcome     string  `json:"outcome"`
	StartedAt   string  `json:"started_at"`
	CompletedAt string  `json:"completed_at"`
	BeadID      string  `json:"bead_id"`
	Harness     string  `json:"harness"`
	Provider    string  `json:"provider"`
	Model       string  `json:"model"`
	CostUSD     float64 `json:"cost_usd"`
	DurationMs  int     `json:"duration_ms"`
	ExitCode    int     `json:"exit_code"`
	TokensIn    int     `json:"tokens_in"`
	TokensOut   int     `json:"tokens_out"`
}

func loadFromRunStore(workingDir string) ([]Attempt, error) {
	dir := filepath.Join(workingDir, runStoreSubdir)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("read run store: %w", err)
	}
	out := make([]Attempt, 0, len(entries))
	for _, entry := range entries {
		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") {
			continue
		}
		raw, err := os.ReadFile(filepath.Join(dir, entry.Name()))
		if err != nil {
			continue
		}
		var rec runRecord
		if err := json.Unmarshal(raw, &rec); err != nil || rec.ID == "" {
			continue
		}
		// Only try-layer records correspond to execute-bead attempts.
		// Run-layer records (per-invocation harness sessions) are noise
		// for Story 11 aggregations; skip them. Empty layer is treated
		// as try for forward-compat with writers that omit it.
		layer := strings.ToLower(rec.Layer)
		if layer != "" && layer != "try" {
			continue
		}
		a := Attempt{
			AttemptID:    rec.ID,
			BeadID:       rec.BeadID,
			Harness:      rec.Harness,
			Provider:     rec.Provider,
			Model:        rec.Model,
			Status:       rec.Status,
			Outcome:      rec.Outcome,
			CostUSD:      rec.CostUSD,
			DurationMS:   rec.DurationMs,
			ExitCode:     rec.ExitCode,
			InputTokens:  rec.TokensIn,
			OutputTokens: rec.TokensOut,
			StartedAt:    parseTime(rec.StartedAt),
			FinishedAt:   parseTime(rec.CompletedAt),
			Source:       SourceRunStore,
		}
		out = append(out, a)
	}
	return out, nil
}

// bundleResult mirrors the subset of agent.ExecuteBeadResult this loader
// reads. Kept local so the package does not depend on the agent package.
type bundleResult struct {
	BeadID     string    `json:"bead_id"`
	AttemptID  string    `json:"attempt_id"`
	Outcome    string    `json:"outcome"`
	Status     string    `json:"status"`
	Harness    string    `json:"harness"`
	Provider   string    `json:"provider"`
	Model      string    `json:"model"`
	DurationMS int       `json:"duration_ms"`
	CostUSD    float64   `json:"cost_usd"`
	ExitCode   int       `json:"exit_code"`
	StartedAt  time.Time `json:"started_at"`
	FinishedAt time.Time `json:"finished_at"`
}

func loadFromBundles(workingDir string) ([]Attempt, error) {
	dir := filepath.Join(workingDir, bundlesSubdir)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("read bundles dir: %w", err)
	}
	out := make([]Attempt, 0, len(entries))
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		bundleID := entry.Name()
		resultPath := filepath.Join(dir, bundleID, "result.json")
		raw, err := os.ReadFile(resultPath)
		if err != nil {
			continue
		}
		var res bundleResult
		if err := json.Unmarshal(raw, &res); err != nil {
			continue
		}
		attemptID := res.AttemptID
		if attemptID == "" {
			attemptID = bundleID
		}
		out = append(out, Attempt{
			AttemptID:  attemptID,
			BeadID:     res.BeadID,
			Harness:    res.Harness,
			Provider:   res.Provider,
			Model:      res.Model,
			Status:     res.Status,
			Outcome:    res.Outcome,
			CostUSD:    res.CostUSD,
			DurationMS: res.DurationMS,
			ExitCode:   res.ExitCode,
			StartedAt:  res.StartedAt,
			FinishedAt: res.FinishedAt,
			Source:     SourceBundle,
		})
	}
	return out, nil
}

// routingFacts is the harness/provider/model the most recent kind:routing
// or kind:escalation-summary event recorded for a bead. Used to fill in
// blanks on legacy attempts whose result.json predates those fields.
type routingFacts struct {
	Harness  string
	Provider string
	Model    string
}

// loadRoutingEnrichment scans the bead store and indexes the most recent
// routing/escalation-summary facts per bead. Best-effort: a missing or
// unreadable bead store yields an empty map, never an error, since the
// loader still has authoritative data on each result.
func loadRoutingEnrichment(workingDir string) (map[string]routingFacts, error) {
	store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
	beads, err := store.ReadAll()
	if err != nil {
		// Return an empty map so missing bead store does not abort
		// metrics loading.
		return map[string]routingFacts{}, nil
	}
	out := make(map[string]routingFacts, len(beads))
	for _, b := range beads {
		facts := routingFromExtra(b.Extra)
		if facts.Harness == "" && facts.Provider == "" && facts.Model == "" {
			continue
		}
		out[b.ID] = facts
	}
	return out, nil
}

// routingFromExtra walks bead.Extra["events"] in chronological order and
// returns the last kind:routing or kind:escalation-summary facts. Both
// kinds carry resolved_provider / resolved_model in the JSON body; the
// escalation summary additionally exposes a tiers_attempted list whose
// final entry is the winning tier.
func routingFromExtra(extra map[string]any) routingFacts {
	if extra == nil {
		return routingFacts{}
	}
	raw, ok := extra["events"]
	if !ok {
		return routingFacts{}
	}
	items, ok := raw.([]any)
	if !ok {
