231	// agentMetricsFingerprint produces a stable revision string for the
232	// agentmetrics inputs at workingDir. The hash inputs are: the .ddx/exec/runs
233	// directory listing (name + size + modtime), the .ddx/executions directory
234	// listing of result.json files, and the .ddx/beads-archive.jsonl file's
235	// stat. Any add/remove/modify in those sources flips the fingerprint and
236	// invalidates the cache. The fingerprint survives ADR-004 archive moves
237	// because the archive file is included.
238	func agentMetricsFingerprint(workingDir string) string {
239		h := sha256.New()
240		addDir(h, filepath.Join(workingDir, ".ddx", "exec", "runs"), "")
241		addDir(h, filepath.Join(workingDir, ".ddx", "executions"), "result.json")
242		addStat(h, filepath.Join(workingDir, ".ddx", "beads-archive.jsonl"))
243		addStat(h, filepath.Join(workingDir, ".ddx", "beads.jsonl"))
244		return fmt.Sprintf("%x", h.Sum(nil))
245	}
