247	func addDir(h interface{ Write([]byte) (int, error) }, dir, requireChild string) {
248		entries, err := os.ReadDir(dir)
249		if err != nil {
250			fmt.Fprintf(writerOf(h), "missing:%s\n", dir)
251			return
252		}
253		names := make([]string, 0, len(entries))
254		for _, e := range entries {
255			names = append(names, e.Name())
256		}
257		sort.Strings(names)
258		for _, name := range names {
259			full := filepath.Join(dir, name)
260			if requireChild != "" {
261				full = filepath.Join(full, requireChild)
262			}
263			addStat(h, full)
264		}
265	}
266	
267	func addStat(h interface{ Write([]byte) (int, error) }, path string) {
268		info, err := os.Stat(path)
269		if err != nil {
270			fmt.Fprintf(writerOf(h), "absent:%s\n", path)
271			return
272		}
273		fmt.Fprintf(writerOf(h), "%s:%d:%d\n", path, info.Size(), info.ModTime().UnixNano())
274	}
